const webhookBody = $input.item.json.body;
const config = $('Config').item.json;

const errorLog = webhookBody?.error_log || '에러 로그 없음';
const branch = webhookBody?.branch || 'unknown';
const buildTitle = webhookBody?.build_title || '';
const author = webhookBody?.author || '';
const buildUrl = webhookBody?.build_url || '';
const buildNumber = webhookBody?.build_number || '';
const jobName = webhookBody?.job_name || '';
const gitCommit = webhookBody?.git_commit || '';
const gitProjectPath = webhookBody?.git_project_path || '';

let jobDisplayMap = {};
try { jobDisplayMap = JSON.parse(config.job_display_names || '{}'); } catch(e) {}
const jobDisplayName = jobDisplayMap[jobName] || jobName;

const prompt = `Jenkins 빌드가 실패했습니다. 에러 로그를 분석해서 실패 원인을 예측하고 해결 방법을 한국어로 간결하게 제안해주세요.\n\n## 빌드 정보\n- 브랜치: ${branch}\n- 작성자: ${author}\n- MR/커밋: ${buildTitle}\n\n## 에러 로그\n\`\`\`\n${errorLog.substring(0, 5000)}\n\`\`\``;

return [{
  json: {
    prompt,
    branch,
    buildTitle,
    author,
    buildUrl,
    buildNumber,
    jobName,
    jobDisplayName,
    gitCommit,
    gitProjectPath,
    errorLog: errorLog.substring(0, 3000)
  }
}];

const changes = $input.item.json.changes || [];
let processedChanges = [];

const skipExtensions = [
  '.jpg', '.jpeg', '.png', '.gif', '.svg', '.ico', '.webp', '.bmp', '.tiff',
  '.mp3', '.wav', '.ogg', '.flac', '.aac', '.m4a',
  '.mp4', '.webm', '.avi', '.mov', '.mkv', '.flv',
  '.pdf', '.doc', '.docx', '.xls', '.xlsx', '.ppt', '.pptx',
  '.zip', '.rar', '.tar', '.gz', '.7z',
  '.bin', '.exe', '.dll', '.so', '.dylib',
  '.ttf', '.otf', '.woff', '.woff2',
  '.psd', '.ai', '.sketch'
];

function shouldProcessFile(filePath) {
  const lowerPath = filePath.toLowerCase();
  for (const ext of skipExtensions) {
    if (lowerPath.endsWith(ext)) return false;
  }
  const skipDirs = ['node_modules/', 'dist/', 'build/'];
  for (const dir of skipDirs) {
    if (lowerPath.includes(dir)) return false;
  }
  return true;
}

function isBinaryContent(diff) {
  if (diff.includes('Binary files') && diff.includes('differ')) return true;
  if (diff.includes('\0')) return true;
  const base64Pattern = /^[A-Za-z0-9+/=]{20,}$/m;
  const lines = diff.split('\n');
  let base64Lines = 0;
  for (let i = 0; i < Math.min(lines.length, 10); i++) {
    if (base64Pattern.test(lines[i])) base64Lines++;
  }
  return base64Lines > 5;
}

function getChangeType(change) {
  const { new_path, old_path, diff } = change;
  if (new_path === '/dev/null' || diff.startsWith('deleted file mode')) return 'delete';
  if (old_path !== new_path && old_path !== '/dev/null') {
    const actualDiffLines = diff.split('\n')
      .filter(line => line.startsWith('+') || line.startsWith('-'))
      .filter(line => !line.startsWith('+++') && !line.startsWith('---'));
    if (actualDiffLines.length === 0) return 'rename';
    return 'rename+modify';
  }
  if (old_path === '/dev/null' || diff.startsWith('new file mode')) return 'add';
  return 'modify';
}

for (const change of changes) {
  const { old_path, new_path, diff } = change;
  const changeType = getChangeType(change);
  if ((changeType === 'add' || changeType === 'modify' || changeType === 'rename+modify') &&
      shouldProcessFile(new_path) &&
      !isBinaryContent(diff)) {
    const isTooLarge = diff.length > 10000;
    const processedDiff = isTooLarge
      ? `${diff.substring(0, 5000)}... (내용 생략) ...${diff.substring(diff.length - 5000)}`
      : diff;
    processedChanges.push({
      file_path: new_path,
      old_path: old_path !== new_path ? old_path : null,
      change_type: changeType,
      is_summarized: isTooLarge,
      diff: processedDiff
    });
  }
}

return { json: { changes: processedChanges } };

const base = $('Build Analysis Prompt').item.json;
const changes = $json.changes || [];

// Set MR Info가 MR URL을 찾았으면 그걸 우선 사용
let resolvedBuildUrl = base.buildUrl;
try {
  const mrUrl = $('Set MR Info').item.json.buildUrl;
  if (mrUrl) resolvedBuildUrl = mrUrl;
} catch(e) {}

let mrSection = '';
if (changes.length > 0) {
  mrSection = '\n\n## 관련 MR 변경 코드\n(빌드 실패 시점 MR 코드 변경사항)\n\n';
  for (const change of changes.slice(0, 5)) {
    mrSection += `### ${change.file_path}\n\`\`\`\n${change.diff.substring(0, 1500)}\n\`\`\`\n\n`;
  }
}

return [{
  json: {
    ...base,
    buildUrl: resolvedBuildUrl,
    prompt: base.prompt + mrSection
  }
}];

const base = $('Build Analysis Prompt').item.json;
const response = $input.item.json;

// GitLab API returns array; n8n may parse as array or single object
const mrList = Array.isArray(response) ? response : [response];
const mr = mrList[0];

if (!mr || !mr.iid) {
  return [{ json: { ...base, mrIid: '', projectPath: '', buildUrl: base.buildUrl } }];
}

const mrIid = String(mr.iid);
const mrWebUrl = mr.web_url || '';
const gitlabBaseUrl = $('Config').item.json.gitlab_base_url;
let projectPath = '';
const pathMatch = mrWebUrl.replace(gitlabBaseUrl, '').match(/^\/(.+?)\/-\/merge_requests/);
if (pathMatch) {
  projectPath = encodeURIComponent(pathMatch[1]);
}

return [{
  json: {
    ...base,
    mrIid,
    projectPath,
    buildUrl: mrWebUrl || base.buildUrl
  }
}];

const b = $('Build Analysis Prompt').item.json;
const buildUrl = $('Enrich AI Prompt').item.json.buildUrl;
const aiOutput = $json.output || '';

let text = '@here\n#### :jenkins5: Jenkins Pipeline Failure :jenkins5:\n';
text += '- **Target Branch:** `' + b.branch + '`\n';
text += '- **Target Build:** [**' + b.jobName + '#' + b.buildNumber + '**](' + $('Jenkins Webhook').first().json.body.build_url + ')\n';
text += '- [**관련 MR 바로 가기 :animal_bingo_head:**](' + buildUrl + ')\n';
text += '---\n';
text += '##### :gunpang_question: AI 예측 원인\n```\n';
text += aiOutput + '\n```\n';
text += '##### :gunpang_paper_log: 에러로그\n```\n';
text += b.errorLog + '\n```';

return [{ json: { text } }];

const branch         = $json.branch;
const buildNumber    = $json.buildNumber;
const jobName        = $json.jobName;

const linkKey = 'link_' + jobName.replace(/-/g, '_') + '_' + branch;
const serviceLinks = $('Config').item.json[linkKey] || '';

let text = '@here\n';
text += '#### :shinchan_dance: Jenkins Pipeline Success :shinchan_dance:\n';
text += '- **대상 브랜치:** `' + branch + '`\n';
text += '- **Target Build:** [**' + jobName + '#' + buildNumber + '**](' + $input.first().json.buildUrl + ')\n';
if (serviceLinks) {
  text += '\n---\n##### 서비스 점검하러 가기 :shin_hyeong_man:\n';
  text += serviceLinks;
}

return [{ json: { text } }];
